+  const lockExists = await exists(lockfilePath);
+  const markerExists = await exists(markerPath);
+  if (!lockExists) {
+    return {
+      manager: params.manager,
+      status: "unknown",
+      lockfilePath,
+      markerPath,
+      reason: "lockfile missing",
+    };
+  }
+  if (!markerExists) {
+    return {
+      manager: params.manager,
+      status: "missing",
+      lockfilePath,
+      markerPath,
+      reason: "node_modules marker missing",
+    };
+  }
