+  const markerMtime = await statMtimeMs(markerPath);
+  if (!lockMtime || !markerMtime) {
+    return {
+      manager: params.manager,
+      status: "unknown",
+      lockfilePath,
+      markerPath,
+    };
+  }
+  if (lockMtime > markerMtime + 1000) {
+    return {
+      manager: params.manager,
+      status: "stale",
+      lockfilePath,
+      markerPath,
+      reason: "lockfile newer than install marker",
+    };
+  }
+  return {
+    manager: params.manager,
+    status: "ok",
+    lockfilePath,
+    markerPath,
+  };
+}
