+import { visibleWidth } from "./ansi.js";
+
+type Align = "left" | "right" | "center";
+
+export type TableColumn = {
+  key: string;
+  header: string;
+  align?: Align;
+  minWidth?: number;
+  maxWidth?: number;
+  flex?: boolean;
+};
+
+export type RenderTableOptions = {
+  columns: TableColumn[];
+  rows: Array<Record<string, string>>;
+  width?: number;
+  padding?: number;
+  border?: "unicode" | "ascii" | "none";
+};
+
+function repeat(ch: string, n: number): string {
+  if (n <= 0) return "";
+  return ch.repeat(n);
+}
+
+function padCell(text: string, width: number, align: Align): string {
+  const w = visibleWidth(text);
+  if (w >= width) return text;
+  const pad = width - w;
+  if (align === "right") return `${repeat(" ", pad)}${text}`;
+  if (align === "center") {
+    const left = Math.floor(pad / 2);
+    const right = pad - left;
+    return `${repeat(" ", left)}${text}${repeat(" ", right)}`;
+  }
+  return `${text}${repeat(" ", pad)}`;
+}
+
+function wrapLine(text: string, width: number): string[] {
+  if (width <= 0) return [text];
+  const words = text.split(/(\s+)/).filter(Boolean);
+  const lines: string[] = [];
+  let current = "";
+  let currentWidth = 0;
+  const push = (value: string) => lines.push(value.replace(/\s+$/, ""));
+
+  const flush = () => {
+    if (current.trim().length === 0) return;
+    push(current);
+    current = "";
+    currentWidth = 0;
+  };
+
+  const breakLong = (word: string) => {
+    const parts: string[] = [];
+    let buf = "";
+    let lastBreakAt = 0;
+    const isBreakChar = (ch: string) =>
+      ch === "/" || ch === "-" || ch === "_" || ch === ".";
+    for (const ch of Array.from(word)) {
+      const next = buf + ch;
+      if (visibleWidth(next) > width && buf) {
+        if (lastBreakAt > 0) {
+          parts.push(buf.slice(0, lastBreakAt));
+          buf = `${buf.slice(lastBreakAt)}${ch}`;
+          lastBreakAt = 0;
+          for (let i = 0; i < buf.length; i += 1) {
+            const c = buf[i];
+            if (c && isBreakChar(c)) lastBreakAt = i + 1;
+          }
+        } else {
+          parts.push(buf);
+          buf = ch;
+        }
+      } else {
+        buf = next;
+        if (isBreakChar(ch)) lastBreakAt = buf.length;
+      }
+    }
+    if (buf) parts.push(buf);
+    return parts;
+  };
+
+  for (const token of words) {
+    const tokenWidth = visibleWidth(token);
+    const isSpace = /^\s+$/.test(token);
+
+    if (tokenWidth > width && !isSpace) {
+      flush();
+      for (const part of breakLong(token.replace(/^\s+/, ""))) {
+        push(part);
+      }
+      continue;
+    }
+
+    if (
+      currentWidth + tokenWidth > width &&
+      current.trim().length > 0 &&
+      !isSpace
+    ) {
+      flush();
+    }
+
+    current += token;
+    currentWidth = visibleWidth(current);
+  }
