+    const shrink = (order: number[], minWidths: number[]) => {
+      while (over > 0) {
+        let progressed = false;
+        for (const i of order) {
+          if ((widths[i] ?? 0) <= (minWidths[i] ?? 0)) continue;
+          widths[i] = (widths[i] ?? 0) - 1;
+          over -= 1;
+          progressed = true;
+          if (over <= 0) break;
+        }
+        if (!progressed) break;
+      }
+    };
