+  const box =
+    border === "ascii"
+      ? {
+          tl: "+",
+          tr: "+",
+          bl: "+",
+          br: "+",
+          h: "-",
+          v: "|",
+          t: "+",
+          ml: "+",
+          m: "+",
+          mr: "+",
+          b: "+",
+        }
+      : {
+          tl: "┌",
+          tr: "┐",
+          bl: "└",
+          br: "┘",
+          h: "─",
+          v: "│",
+          t: "┬",
+          ml: "├",
+          m: "┼",
+          mr: "┤",
+          b: "┴",
+        };
